// Multilingual detail content for the Prophets pages.
//
// This file ADDS a 14-language layer (and a Quran/Sunnah-only family model) on top
// of the structural data in `prophets.ts`. The detail component localizes from here
// and falls back to the English in `prophets.ts` for any prophet not yet present, so
// the page never breaks mid-rollout.
//
// Rules: Arabic script (arabicName) stays as-is. Family members are listed ONLY where
// named in the Quran or authentic Sunnah; otherwise the entry is omitted or marked
// "not named in authentic sources". The ﷺ symbol and transliterations are preserved.

import type { Lang } from '@/lib/i18n/translations';

export type ProphetLangMap = Record<Lang, string>;

export interface PDLineageEntry {
  arabicName: string;
  name: ProphetLangMap;
  relation: ProphetLangMap;
}

export interface PDFamilyMember {
  arabicName?: string;
  name: ProphetLangMap;
  note?: ProphetLangMap;
}

export interface PDFamily {
  father?: PDFamilyMember;
  mother?: PDFamilyMember;
  wives?: PDFamilyMember[];
  sons?: PDFamilyMember[];
  daughters?: PDFamilyMember[];
  brothers?: PDFamilyMember[];
  sisters?: PDFamilyMember[];
}

export interface ProphetDetail {
  name: ProphetLangMap;
  alternativeNames: ProphetLangMap[];
  title: ProphetLangMap;
  nationSentTo: ProphetLangMap;
  periodInHistory: ProphetLangMap;
  lifespan: ProphetLangMap;
  burialPlace: ProphetLangMap;
  message: ProphetLangMap;
  specialCharacteristics: ProphetLangMap;
  family: PDFamily;
  keyMiracles: ProphetLangMap[];
  keyStories: ProphetLangMap[];
}

